// NewUpdatePortalPayload builds a portals service updatePortal endpoint
// payload.
func NewUpdatePortalPayload(body *UpdatePortalRequestBody, sessionToken *string, apikeyToken *string, projectSlugInput *string) *portals.UpdatePortalPayload {
	v := &portals.UpdatePortalPayload{
		Enabled:     body.Enabled,
		DisplayName: body.DisplayName,
		Tagline:     body.Tagline,
		LogoAssetID: body.LogoAssetID,
	}
	v.SessionToken = sessionToken
	v.ApikeyToken = apikeyToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

// ValidateUpdatePortalRequestBody runs the validations defined on
// UpdatePortalRequestBody
func ValidateUpdatePortalRequestBody(body *UpdatePortalRequestBody) (err error) {
	if body.LogoAssetID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.logo_asset_id", *body.LogoAssetID, goa.FormatUUID))
	}
	return
}
